  ('elementary-f29af906-moex-00582', 'elementary-f29af906', 'elementary-f29af906-moex-112-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '甲所有權人在乙市的都市計畫範圍內土地採取土石，違反乙市依都市計畫法所發布之命令，乙市 主管機關丙處甲罰鍰之外，並勒令其恢復原狀，甲卻拒不恢復原狀者，得按次處罰。下列敘述何者 正確？', '["丙對甲之採取行為，若予按次處罰，將違反一行為不二罰原則", "丙對甲之工地處所，得採取強制斷水或斷電之裁罰性行政處分", "若甲拒不恢復原狀後，主管機關裁處前，罰則變動為處罰額度較重者，應適用舊法予以處罰", "依行政罰法，罰鍰為金錢制裁，並不以故意或過失為責任要件"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:53+00:00", "source_pdf_sha1": "66725031cfef", "answer_pdf_sha1": "54cf3b410240", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "512", "s": "0404", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
